import numpy as np

def hafnian(matrix: np.ndarray) -> complex:
    n = matrix.shape[0]
    if n == 0:
        return 1.0
    if n == 2:
        return matrix[0, 1]
    if n % 2 == 1:
        return 0.0

    result = 0.0
    for j in range(1, n):
        # Pair element 0 with element j
        remaining = [i for i in range(n) if i not in (0, j)]
        if len(remaining) == 0:
            result += matrix[0, j]
        else:
            submatrix = matrix[np.ix_(remaining, remaining)]
            result += matrix[0, j] * hafnian(submatrix)

    return result
